Node mergeLists(Node a, Node b){
  Node dummy = new Node(0), tail = dummy;
  while(a != null && b != null){
    if(a.val <= b.val){ tail.next = a; a = a.next; }
    else { tail.next = b; b = b.next; }
    tail = tail.next;
  }
  tail.next = (a != null) ? a : b;
  return dummy.next;
}

