  char[] x = a.toCharArray(), y = b.toCharArray();
  Arrays.sort(x); Arrays.sort(y);
  return Arrays.equals(x, y);
}

void subsets(int[] nums, int idx, List<Integer> current, List<List<Integer>> result){
  if(idx == nums.length){
    result.add(new ArrayList<>(current));
    return;
  }
  subsets(nums, idx+1, current, result); // exclude
  current.add(nums[idx]);
  subsets(nums, idx+1, current, result); // include
  current.remove(current.size()-1);
}

String longestPalindrome(String s){
  int start = 0, maxLen = 0;
  for(int i = 0; i < s.length(); i++){
    for(int center = i; center <= i+1; center++){
      int l = i, r = center;
      while(l >= 0 && r < s.length() && s.charAt(l) == s.charAt(r)){ l--; r++; }
      if(r - l - 1 > maxLen){ maxLen = r - l - 1; start = l + 1; }
    }
  }
  return s.substring(start, start + maxLen);
}

class QueueUsingStacks {
  Deque<Integer> in = new ArrayDeque<>(), out = new ArrayDeque<>();
  void enqueue(int x){ in.push(x); }
  int dequeue(){
    if(out.isEmpty()){
      while(!in.isEmpty()) out.push(in.pop());
    }
    return out.pop();
  }
}

int equilibriumIndex(int[] arr){
  int total = 0;
  for(int x : arr) total += x;
  int leftSum = 0;
  for(int i = 0; i < arr.length; i++){
    total -= arr[i];
    if(leftSum == total) return i;
    leftSum += arr[i];
  }
  return -1;
}

